pub fn fold(cp: u21) u21 {
    var special_lo: usize = 0;
    var special_hi: usize = fold_specials.len;
    while (special_lo < special_hi) {
        const mid = special_lo + (special_hi - special_lo) / 2;
        const entry = fold_specials[mid];
        if (cp < entry.cp) {
            special_hi = mid;
        } else if (cp > entry.cp) {
            special_lo = mid + 1;
        } else {
            return entry.folded;
        }
    }

    var lo: usize = 0;
    var hi: usize = fold_ranges.len;
    while (lo < hi) {
        const mid = lo + (hi - lo) / 2;
        const range = fold_ranges[mid];
        if (cp < range.start) {
            hi = mid;
        } else if (cp > range.end) {
            lo = mid + 1;
        } else {
            const folded: i32 = @as(i32, @intCast(cp)) + range.delta;
            return @intCast(folded);
        }
    }
    return cp;
}
